std::vector<Human> humans;
bool wall[31][31];

// BFS path finding - returns move character to get from start toward target
// Avoids walls and optionally avoids given set of blocked cells
char bfs_move(Point start, Point target, const std::vector<Point>& extra_blocked) {
    if (start == target) return '.';

    static int dist[31][31];
    static Point parent[31][31];
    memset(dist, -1, sizeof(dist));

    std::queue<Point> q;
    dist[start.r][start.c] = 0;
    parent[start.r][start.c] = {-1, -1};
    q.push(start);

    while (!q.empty()) {
        Point cur = q.front(); q.pop();

        for (int d = 0; d < 4; d++) {
            Point np = {cur.r + DIRS[d].r, cur.c + DIRS[d].c};
            if (np.r < 1 || np.r > GRID_SIZE || np.c < 1 || np.c > GRID_SIZE) continue;
            if (wall[np.r][np.c]) continue;
            if (dist[np.r][np.c] != -1) continue;

            bool blocked = false;
            for (const auto& b : extra_blocked) {
                if (np == b) { blocked = true; break; }
            }
            if (blocked) continue;

            dist[np.r][np.c] = dist[cur.r][cur.c] + 1;
            parent[np.r][np.c] = cur;
            q.push(np);

            if (np == target) {
                // Trace back to first step
                Point step = np;
                while (!(parent[step.r][step.c] == start)) {
                    step = parent[step.r][step.c];
                }
                for (int i = 0; i < 4; i++) {
                    if (start.r + DIRS[i].r == step.r && start.c + DIRS[i].c == step.c) {
                        return DIR_MOVE[i];
                    }
                }
                return '.';
            }
        }
    }
    return '.';
}

// Check if we can build a wall at pos (no pet on it, no pet adjacent to it, no human on it except builder)
bool can_build_wall(Point pos, int builder_id) {
    if (pos.r < 1 || pos.r > GRID_SIZE || pos.c < 1 || pos.c > GRID_SIZE) return false;
    if (wall[pos.r][pos.c]) return false;

    for (const auto& pet : pets) {
        if (pet.pos == pos) return false;
        if (std::abs(pet.pos.r - pos.r) + std::abs(pet.pos.c - pos.c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (i == builder_id) continue;
        if (humans[i].pos == pos) return false;
    }
    return true;
}

// Count pets in a horizontal band [r_start, r_end]
int count_pets_in_band(int r_start, int r_end) {
    int count = 0;
    for (const auto& pet : pets) {
        if (pet.pos.r >= r_start && pet.pos.r <= r_end) count++;
    }
    return count;
}

// Compute reachable area size from a point (using BFS through passable squares)
int reachable_area(Point start) {
    if (wall[start.r][start.c]) return 0;
    static bool visited[31][31];
    memset(visited, false, sizeof(visited));
    std::queue<Point> q;
    q.push(start);
    visited[start.r][start.c] = true;
    int area = 0;
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        area++;
        for (int d = 0; d < 4; d++) {
