    int pets_mid = count_pets_in_band(best_wall1 + 1, best_wall2 - 1);
    int pets_bot = count_pets_in_band(best_wall2 + 1, GRID_SIZE);

    int section_sizes[3] = {
        (best_wall1 - 1) * GRID_SIZE,
        (best_wall2 - best_wall1 - 1) * GRID_SIZE,
        (GRID_SIZE - best_wall2) * GRID_SIZE
    };
    int section_pets[3] = {pets_top, pets_mid, pets_bot};

    int target_section = 0;
    double best_section_score = -1;
    for (int s = 0; s < 3; s++) {
        if (section_sizes[s] < 30) continue;
        double s_val = (double)section_sizes[s] / 900.0 * std::pow(2.0, -(double)section_pets[s]);
        if (s_val > best_section_score) {
            best_section_score = s_val;
            target_section = s;
        }
    }

    // Target row range for humans
    int target_r_start, target_r_end;
    if (target_section == 0) {
        target_r_start = 1; target_r_end = best_wall1 - 1;
    } else if (target_section == 1) {
        target_r_start = best_wall1 + 1; target_r_end = best_wall2 - 1;
    } else {
        target_r_start = best_wall2 + 1; target_r_end = GRID_SIZE;
    }

    // Build plan: which wall cells need to be built
    // We need to build wall at best_wall1 (all 30 cols) and best_wall2 (all 30 cols)
    // But we only strictly need the walls that border our target section
    std::vector<Point> walls_needed;

    // Both walls are needed to fully isolate sections
    for (int c = 1; c <= GRID_SIZE; c++) {
        walls_needed.push_back({best_wall1, c});
        walls_needed.push_back({best_wall2, c});
    }

    // Phase tracking
    enum Phase { BUILDING, MIGRATING, DONE };
    Phase phase = BUILDING;

    // Human targets for the safe zone center
    Point safe_center = {(target_r_start + target_r_end) / 2, GRID_SIZE / 2};

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> tentative_walls;

        // Remove completed walls from needed list
        walls_needed.erase(
            std::remove_if(walls_needed.begin(), walls_needed.end(),
                [](const Point& p) { return wall[p.r][p.c]; }),
            walls_needed.end()
        );

        if (walls_needed.empty()) {
            phase = MIGRATING;
        }

        if (phase == BUILDING) {
            // Each human tries to build the nearest unbuilt wall cell
            for (int i = 0; i < M; i++) {
                Point hpos = humans[i].pos;

                // Find best wall to build: closest wall cell that we can build from an adjacent position
                Point best_wall_cell = {-1, -1};
                int best_dist = INF;
                int best_build_dir = -1;

                for (const auto& wc : walls_needed) {
                    if (wall[wc.r][wc.c]) continue;

                    // Check if human is already adjacent and can build
                    for (int d = 0; d < 4; d++) {
                        Point stand_pos = {wc.r + DIRS[d].r, wc.c + DIRS[d].c};
                        if (stand_pos == hpos) {
                            // We're already adjacent!
                            if (can_build_wall(wc, i)) {
                                // Check not already tentatively building this
                                bool already_planned = false;
                                for (const auto& tw : tentative_walls) {
                                    if (tw == wc) { already_planned = true; break; }
                                }
                                if (!already_planned) {
                                    // Find direction from human to wall
                                    for (int dd = 0; dd < 4; dd++) {
                                        Point target = {hpos.r + DIRS[dd].r, hpos.c + DIRS[dd].c};
                                        if (target == wc) {
                                            best_wall_cell = wc;
                                            best_dist = 0;
                                            best_build_dir = dd;
                                            goto found_wall;
                                        }
                                    }
                                }
                            }
                        }
                    }

                    // Otherwise compute distance to nearest stand position
                    for (int d = 0; d < 4; d++) {
                        Point stand_pos = {wc.r + DIRS[d].r, wc.c + DIRS[d].c};
                        if (stand_pos.r < 1 || stand_pos.r > GRID_SIZE ||
                            stand_pos.c < 1 || stand_pos.c > GRID_SIZE) continue;
                        if (wall[stand_pos.r][stand_pos.c]) continue;

                        int dist = std::abs(hpos.r - stand_pos.r) + std::abs(hpos.c - stand_pos.c);
                        if (dist < best_dist) {
                            // Check not already tentatively claimed
                            bool already_planned = false;
                            for (const auto& tw : tentative_walls) {
                                if (tw == wc) { already_planned = true; break; }
                            }
                            if (!already_planned) {
                                best_dist = dist;
                                best_wall_cell = wc;
                                best_build_dir = -1; // need to move first
                            }
                        }
                    }
                }

                found_wall:
                if (best_wall_cell.r == -1) {
                    // No buildable wall found, move toward safe zone
                    actions[i] = bfs_move(hpos, safe_center, tentative_walls);
                } else if (best_dist == 0 && best_build_dir >= 0) {
                    // Build it!
                    actions[i] = DIR_BUILD[best_build_dir];
                    tentative_walls.push_back(best_wall_cell);
                } else {
                    // Move toward a stand position adjacent to the best wall cell
                    Point best_stand = {-1, -1};
                    int best_sd = INF;
                    for (int d = 0; d < 4; d++) {
                        Point stand_pos = {best_wall_cell.r + DIRS[d].r, best_wall_cell.c + DIRS[d].c};
                        if (stand_pos.r < 1 || stand_pos.r > GRID_SIZE ||
                            stand_pos.c < 1 || stand_pos.c > GRID_SIZE) continue;
                        if (wall[stand_pos.r][stand_pos.c]) continue;
                        int sd = std::abs(hpos.r - stand_pos.r) + std::abs(hpos.c - stand_pos.c);
                        if (sd < best_sd) {
                            best_sd = sd;
                            best_stand = stand_pos;
                        }
                    }
                    if (best_stand.r != -1) {
                        actions[i] = bfs_move(hpos, best_stand, tentative_walls);
                    }
                    // Reserve this wall so others don't also target it
                    tentative_walls.push_back(best_wall_cell);
                }
            }
        } else {
            // MIGRATING or DONE: move humans to center of safe zone
            for (int i = 0; i < M; i++) {
                Point hpos = humans[i].pos;
                // Spread humans out a bit in the safe zone
                int target_c = 2 + (i * (GRID_SIZE - 3)) / std::max(1, M - 1);
                if (M == 1) target_c = GRID_SIZE / 2;
                Point target = {(target_r_start + target_r_end) / 2, target_c};

                // Clamp to safe zone
                target.r = std::max(target_r_start, std::min(target_r_end, target.r));
                target.c = std::max(1, std::min(GRID_SIZE, target.c));

                if (hpos == target) {
                    actions[i] = '.';
                } else {
                    actions[i] = bfs_move(hpos, target, tentative_walls);
                }
            }
        }

        // Validate actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            Point hpos = humans[i].pos;

            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_BUILD[dd]) { d = dd; break; }
                }
                Point wp = {hpos.r + DIRS[d].r, hpos.c + DIRS[d].c};
                if (!can_build_wall(wp, i)) {
                    actions[i] = '.';
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
                }
                Point np = {hpos.r + DIRS[d].r, hpos.c + DIRS[d].c};
                if (np.r < 1 || np.r > GRID_SIZE || np.c < 1 || np.c > GRID_SIZE || wall[np.r][np.c]) {
                    actions[i] = '.';
                }
            }
        }

        // Output
        std::cout << actions << std::endl;

        // Apply wall builds
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_BUILD[dd]) { d = dd; break; }
                }
                Point wp = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                if (wp.r >= 1 && wp.r <= GRID_SIZE && wp.c >= 1 && wp.c <= GRID_SIZE) {
                    wall[wp.r][wp.c] = true;
                }
            }
        }

        // Apply moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
                }
                Point np = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                if (np.r >= 1 && np.r <= GRID_SIZE && np.c >= 1 && np.c <= GRID_SIZE && !wall[np.r][np.c]) {
                    humans[i].pos = np;
                }
            }
        }

        // Read pet moves
        for (int i = 0; i < N; i++) {
            std::string pmove;
            std::cin >> pmove;
            if (pmove == ".") continue;
            for (char c : pmove) {
                for (int d = 0; d < 4; d++) {
                    if (c == DIR_MOVE[d]) {
                        pets[i].pos.r += DIRS[d].r;
                        pets[i].pos.c += DIRS[d].c;
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
