# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = 1000000;

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const Point DIRS[4] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
const char DIR_BUILD[4] = {'u', 'd', 'l', 'r'};
const char DIR_MOVE[4] = {'U', 'D', 'L', 'R'};

struct Pet {
    Point pos;
    int type;
};

struct Human {
    Point pos;
};

int N, M;
std::vector<Pet> pets;
std::vector<Human> humans;
bool wall[31][31];

int bfs_dist[31][31];
Point bfs_parent[31][31];

char bfs_move(Point start, Point target, const std::vector<Point>& extra_blocked) {
    if (start == target) return '.';

    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[start.r][start.c] = 0;
    bfs_parent[start.r][start.c] = {-1, -1};
    q.push(start);

    while (!q.empty()) {
        Point cur = q.front(); q.pop();

        for (int d = 0; d < 4; d++) {
            Point np = {cur.r + DIRS[d].r, cur.c + DIRS[d].c};
            if (np.r < 1 || np.r > GRID_SIZE || np.c < 1 || np.c > GRID_SIZE) continue;
            if (wall[np.r][np.c]) continue;
            if (bfs_dist[np.r][np.c] != -1) continue;

            bool blocked = false;
            for (const auto& b : extra_blocked) {
                if (np == b) { blocked = true; break; }
            }
            if (blocked) continue;

            bfs_dist[np.r][np.c] = bfs_dist[cur.r][cur.c] + 1;
            bfs_parent[np.r][np.c] = cur;
            q.push(np);

            if (np == target) {
                Point step = np;
                while (!(bfs_parent[step.r][step.c] == start)) {
                    step = bfs_parent[step.r][step.c];
                }
                for (int i = 0; i < 4; i++) {
                    if (start.r + DIRS[i].r == step.r && start.c + DIRS[i].c == step.c) {
                        return DIR_MOVE[i];
                    }
                }
                return '.';
            }
        }
    }
    return '.';
}

int bfs_distance(Point start, Point target) {
    if (start == target) return 0;
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[start.r][start.c] = 0;
    q.push(start);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            Point np = {cur.r + DIRS[d].r, cur.c + DIRS[d].c};
            if (np.r < 1 || np.r > GRID_SIZE || np.c < 1 || np.c > GRID_SIZE) continue;
            if (wall[np.r][np.c]) continue;
            if (bfs_dist[np.r][np.c] != -1) continue;
            bfs_dist[np.r][np.c] = bfs_dist[cur.r][cur.c] + 1;
            if (np == target) return bfs_dist[np.r][np.c];
            q.push(np);
        }
    }
    return INF;
}

bool can_build_wall(Point pos, int builder_id) {
    if (pos.r < 1 || pos.r > GRID_SIZE || pos.c < 1 || pos.c > GRID_SIZE) return false;
    if (wall[pos.r][pos.c]) return false;

    for (const auto& pet : pets) {
        if (pet.pos == pos) return false;
        if (std::abs(pet.pos.r - pos.r) + std::abs(pet.pos.c - pos.c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (i == builder_id) continue;
        if (humans[i].pos == pos) return false;
    }
    return true;
}

int count_pets_in_band(int r_start, int r_end) {
    int count = 0;
    for (const auto& pet : pets) {
        if (pet.pos.r >= r_start && pet.pos.r <= r_end) count++;
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].pos.r >> pets[i].pos.c >> pets[i].type;
    }
    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].pos.r >> humans[i].pos.c;
    }

    memset(wall, false, sizeof(wall));

    // Strategy: Pick the best single horizontal wall or pair of walls.
    // For a single wall at row w: creates sections [1..w-1] and [w+1..30].
    // For a pair at w1, w2: creates [1..w1-1], [w1+1..w2-1], [w2+1..30].
    // We also consider corner rectangles that use 2 grid boundaries.

    // Evaluate all options
    struct Option {
        int type; // 0=single wall, 1=pair, 2=corner rect
        int w1, w2; // wall rows (or for corner: w1=wall row, w2=wall col)
        int target_r_start, target_r_end, target_c_start, target_c_end;
        int area;
        int n_pets;
        int n_walls_needed;
        double score;
    };

    std::vector<Option> options;

    // Single horizontal wall options
    for (int w = 4; w <= GRID_SIZE - 3; w++) {
        // Top section [1..w-1]
        int pets_top = count_pets_in_band(1, w - 1);
        int area_top = (w - 1) * GRID_SIZE;
        int walls_top = GRID_SIZE; // one row
        double score_top = (double)area_top / 900.0 * std::pow(2.0, -(double)pets_top);
        options.push_back({0, w, 0, 1, w - 1, 1, GRID_SIZE, area_top, pets_top, walls_top, score_top});

        // Bottom section [w+1..30]
        int pets_bot = count_pets_in_band(w + 1, GRID_SIZE);
        int area_bot = (GRID_SIZE - w) * GRID_SIZE;
        int walls_bot = GRID_SIZE;
        double score_bot = (double)area_bot / 900.0 * std::pow(2.0, -(double)pets_bot);
        options.push_back({0, w, 0, w + 1, GRID_SIZE, 1, GRID_SIZE, area_bot, pets_bot, walls_bot, score_bot});
    }

    // Two horizontal walls
    for (int w1 = 3; w1 <= GRID_SIZE - 6; w1 += 2) {
        for (int w2 = w1 + 4; w2 <= GRID_SIZE - 2; w2 += 2) {
            // Middle section [w1+1..w2-1]
            int pets_mid = count_pets_in_band(w1 + 1, w2 - 1);
            int area_mid = (w2 - w1 - 1) * GRID_SIZE;
            int walls_mid = 2 * GRID_SIZE;
            double score_mid = (double)area_mid / 900.0 * std::pow(2.0, -(double)pets_mid);
            options.push_back({1, w1, w2, w1 + 1, w2 - 1, 1, GRID_SIZE, area_mid, pets_mid, walls_mid, score_mid});
        }
    }

    // Corner rectangles: top-left corner with wall on bottom and right
    for (int h = 5; h <= 20; h++) {
        for (int w = 5; w <= 20; w++) {
            // Rectangle [1..h] x [1..w], walls at row h+1 (cols 1..w) and col w+1 (rows 1..h)
            if (h + 1 > GRID_SIZE || w + 1 > GRID_SIZE) continue;
            int n_pets_in = 0;
            for (const auto& pet : pets) {
                if (pet.pos.r >= 1 && pet.pos.r <= h && pet.pos.c >= 1 && pet.pos.c <= w) n_pets_in++;
            }
            int area = h * w;
            int walls_needed = w + h; // row h+1 cols 1..w, col w+1 rows 1..h
            double score = (double)area / 900.0 * std::pow(2.0, -(double)n_pets_in);
            options.push_back({2, h, w, 1, h, 1, w, area, n_pets_in, walls_needed, score});
        }
    }

    // Pick best option, with tie-breaking favoring fewer walls (faster completion)
    std::sort(options.begin(), options.end(), [](const Option& a, const Option& b) {
        if (std::abs(a.score - b.score) > 0.001) return a.score > b.score;
        return a.n_walls_needed < b.n_walls_needed;
    });

    Option best = options[0];

    // Generate wall cells needed
    std::vector<Point> walls_needed;

    if (best.type == 0) {
        // Single horizontal wall at row w1
        for (int c = 1; c <= GRID_SIZE; c++) {
            walls_needed.push_back({best.w1, c});
        }
    } else if (best.type == 1) {
        // Two horizontal walls
        for (int c = 1; c <= GRID_SIZE; c++) {
            walls_needed.push_back({best.w1, c});
            walls_needed.push_back({best.w2, c});
        }
    } else {
        // Corner rectangle: wall at row (h+1) cols 1..w, col (w+1) rows 1..h
        int h = best.w1, w = best.w2;
        for (int c = 1; c <= w; c++) {
            walls_needed.push_back({h + 1, c});
        }
        for (int r = 1; r <= h; r++) {
            walls_needed.push_back({r, w + 1});
        }
    }

    int target_r_start = best.target_r_start;
    int target_r_end = best.target_r_end;
    int target_c_start = best.target_c_start;
    int target_c_end = best.target_c_end;

    // Phase 1: Move all humans to the safe zone, then build walls from inside
    // Phase 2: Build walls
    // Phase 3: Stay put

    enum Phase { MOVE_IN, BUILD, STAY };
    Phase phase = MOVE_IN;
    int move_in_deadline = 60; // After this many turns, start building regardless

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> tentative_walls;

        // Remove completed walls
        walls_needed.erase(
            std::remove_if(walls_needed.begin(), walls_needed.end(),
                [](const Point& p) { return wall[p.r][p.c]; }),
            walls_needed.end()
        );

        // Check if all humans are in safe zone
        bool all_in_safe = true;
        for (int i = 0; i < M; i++) {
            Point hp = humans[i].pos;
            if (hp.r < target_r_start || hp.r > target_r_end ||
                hp.c < target_c_start || hp.c > target_c_end) {
                all_in_safe = false;
                break;
            }
        }

        if (phase == MOVE_IN) {
            if (all_in_safe || turn >= move_in_deadline) {
                phase = BUILD;
            }
        }

        if (walls_needed.empty()) {
            phase = STAY;
        }

        if (phase == MOVE_IN) {
            // Move each human toward center of safe zone
            Point center = {(target_r_start + target_r_end) / 2, (target_c_start + target_c_end) / 2};
            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;
                if (hp.r >= target_r_start && hp.r <= target_r_end &&
                    hp.c >= target_c_start && hp.c <= target_c_end) {
                    // Already in safe zone, wait or help build
                    actions[i] = '.';
                } else {
                    actions[i] = bfs_move(hp, center, tentative_walls);
                }
            }
        } else if (phase == BUILD) {
            // Assign wall cells to humans greedily
            std::vector<bool> wall_assigned(walls_needed.size(), false);

            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;

                // Find closest unassigned wall cell that this human can potentially build
                int best_idx = -1;
                int best_cost = INF;
                int best_dir = -1;

                for (int j = 0; j < (int)walls_needed.size(); j++) {
                    if (wall_assigned[j]) continue;
                    Point wc = walls_needed[j];
                    if (wall[wc.r][wc.c]) continue;

                    // Check if human is adjacent and can build now
                    for (int d = 0; d < 4; d++) {
                        Point stand = {wc.r + DIRS[d].r, wc.c + DIRS[d].c};
                        if (stand == hp) {
                            // Already adjacent
