Point bfs_parent[31][31];

char bfs_move(Point start, Point target, const std::vector<Point>& extra_blocked) {
    if (start == target) return '.';

    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[start.r][start.c] = 0;
    bfs_parent[start.r][start.c] = {-1, -1};
    q.push(start);

    while (!q.empty()) {
        Point cur = q.front(); q.pop();

        for (int d = 0; d < 4; d++) {
            Point np = {cur.r + DIRS[d].r, cur.c + DIRS[d].c};
            if (np.r < 1 || np.r > GRID_SIZE || np.c < 1 || np.c > GRID_SIZE) continue;
            if (wall[np.r][np.c]) continue;
