            for (const auto& b : extra_blocked) {
                if (np == b) { blocked = true; break; }
            }
            if (blocked) continue;

            bfs_dist[np.r][np.c] = bfs_dist[cur.r][cur.c] + 1;
            bfs_parent[np.r][np.c] = cur;
            q.push(np);

            if (np == target) {
                Point step = np;
                while (!(bfs_parent[step.r][step.c] == start)) {
                    step = bfs_parent[step.r][step.c];
