            if (GRID_SIZE - h >= 1 && GRID_SIZE - w >= 1) {
                int r_start = GRID_SIZE - h + 1;
                int r_wall = r_start - 1;
                int c_start = GRID_SIZE - w + 1;
                int c_wall = c_start - 1;
                if (r_wall >= 1 && c_wall >= 1) {
                    int pets_in = 0;
                    for (const auto& pet : pets) {
                        if (pet.pos.r >= r_start && pet.pos.r <= GRID_SIZE && pet.pos.c >= c_start && pet.pos.c <= GRID_SIZE) pets_in++;
                    }
                    int area = h * w;
                    double sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
                    std::vector<Point> ws;
                    for (int c = c_start; c <= GRID_SIZE; c++) ws.push_back({r_wall, c});
                    for (int r = r_start; r <= GRID_SIZE; r++) ws.push_back({r, c_wall});
                    options.push_back({r_start, GRID_SIZE, c_start, GRID_SIZE, ws, pets_in, area, sc});
                }
