    // Score each option considering feasibility (wall count vs turns available)
    // Penalize options where walls are too numerous to complete in time
    for (auto& opt : options) {
        int nw = opt.walls.size();
        // Each human can build ~1 wall per 2 turns (move + build). With M humans, ~150*M walls max.
        // But realistically much less. Penalize if nw > reasonable
        double feasibility = 1.0;
        int max_walls = M * 100; // generous estimate
        if (nw > max_walls) {
            feasibility = (double)max_walls / nw;
        }
        opt.score *= feasibility;
    }

    // Pick best
    std::sort(options.begin(), options.end(), [](const Option& a, const Option& b) {
        return a.score > b.score;
    });

    auto best = options[0];

