                int human_idx, wall_idx, dist;
            };
            std::vector<HumanWallDist> pairs;
            for (int i = 0; i < M; i++) {
                for (int j = 0; j < (int)walls_needed.size(); j++) {
                    Point wc = walls_needed[j];
                    int min_d = INF;
                    for (int d = 0; d < 4; d++) {
                        Point stand = {wc.r + DIRS[d].r, wc.c + DIRS[d].c};
                        if (stand.r < 1 || stand.r > GRID_SIZE || stand.c < 1 || stand.c > GRID_SIZE) continue;
                        if (wall_grid[stand.r][stand.c]) continue;
                        int dist = std::abs(humans[i].pos.r - stand.r) + std::abs(humans[i].pos.c - stand.c);
                        min_d = std::min(min_d, dist);
                    }
                    if (min_d < INF) {
                        pairs.push_back({i, j, min_d});
                    }
                }
            }
            std::sort(pairs.begin(), pairs.end(), [](const HumanWallDist& a, const HumanWallDist& b) {
                return a.dist < b.dist;
            });

            std::vector<bool> human_assigned(M, false);
            for (const auto& p : pairs) {
                if (human_assigned[p.human_idx] || wall_taken[p.wall_idx]) continue;
                assignment[p.human_idx] = p.wall_idx;
                human_assigned[p.human_idx] = true;
                wall_taken[p.wall_idx] = true;
            }

            // Execute actions
            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;

                if (assignment[i] == -1) {
                    // No wall assigned, move to safe center
                    actions[i] = bfs_move(hp, center_safe, tentative_walls);
                    continue;
                }

                Point wc = walls_needed[assignment[i]];

                // Check if adjacent and can build
                bool can_build_now = false;
                int build_dir = -1;
                for (int d = 0; d < 4; d++) {
                    Point target = {hp.r + DIRS[d].r, hp.c + DIRS[d].c};
                    if (target == wc && can_build_wall(wc, i)) {
                        bool already_tent = false;
                        for (const auto& tw : tentative_walls) {
                            if (tw == wc) { already_tent = true; break; }
                        }
                        if (!already_tent) {
                            can_build_now = true;
                            build_dir = d;
                            break;
                        }
                    }
                }

                if (can_build_now) {
                    actions[i] = DIR_BUILD[build_dir];
                    tentative_walls.push_back(wc);
                } else {
                    // Move toward best stand position
                    Point best_stand = {-1, -1};
                    int best_sd = INF;
                    for (int d = 0; d < 4; d++) {
                        Point stand = {wc.r + DIRS[d].r, wc.c + DIRS[d].c};
                        if (stand.r < 1 || stand.r > GRID_SIZE || stand.c < 1 || stand.c > GRID_SIZE) continue;
                        if (wall_grid[stand.r][stand.c]) continue;
                        int sd = std::abs(hp.r - stand.r) + std::abs(hp.c - stand.c);
                        if (sd < best_sd) {
                            best_sd = sd;
                            best_stand = stand;
                        }
                    }
                    if (best_stand.r != -1) {
                        actions[i] = bfs_move(hp, best_stand, tentative_walls);
                    }
                }
            }
        } else {
            // Building done: move humans to safe center area
            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;
                int target_c = target_c_start + 1 + (i * std::max(0, target_c_end - target_c_start - 2)) / std::max(1, M - 1);
                Point target = {(target_r_start + target_r_end) / 2, target_c};
                target.r = std::max(target_r_start, std::min(target_r_end, target.r));
                target.c = std::max(target_c_start, std::min(target_c_end, target.c));

                if (hp == target) {
                    actions[i] = '.';
                } else {
                    actions[i] = bfs_move(hp, target, tentative_walls);
                }
            }
        }

        // Validate actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            Point hpos = humans[i].pos;

            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_BUILD[dd]) { d = dd; break; }
                }
                Point wp = {hpos.r + DIRS[d].r, hpos.c + DIRS[d].c};
                if (!can_build_wall(wp, i)) {
                    actions[i] = '.';
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
                }
                Point np = {hpos.r + DIRS[d].r, hpos.c + DIRS[d].c};
                if (np.r < 1 || np.r > GRID_SIZE || np.c < 1 || np.c > GRID_SIZE || wall_grid[np.r][np.c]) {
                    actions[i] = '.';
                }
            }
        }

        // Output
        std::cout << actions << std::endl;

        // Apply wall builds
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_BUILD[dd]) { d = dd; break; }
                }
                Point wp = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                if (wp.r >= 1 && wp.r <= GRID_SIZE && wp.c >= 1 && wp.c <= GRID_SIZE) {
                    wall_grid[wp.r][wp.c] = true;
                }
            }
        }

        // Apply moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
                }
                Point np = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                if (np.r >= 1 && np.r <= GRID_SIZE && np.c >= 1 && np.c <= GRID_SIZE && !wall_grid[np.r][np.c]) {
                    humans[i].pos = np;
                }
            }
        }

        // Read pet moves
        for (int i = 0; i < N; i++) {
            std::string pmove;
            std::cin >> pmove;
            if (pmove == ".") continue;
            for (char c : pmove) {
                for (int d = 0; d < 4; d++) {
                    if (c == DIR_MOVE[d]) {
                        pets[i].pos.r += DIRS[d].r;
                        pets[i].pos.c += DIRS[d].c;
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
