    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].pos.r >> pets[i].pos.c >> pets[i].type;
    }
    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].pos.r >> humans[i].pos.c;
    }

    memset(wall_grid, false, sizeof(wall_grid));

    // Evaluate all possible rectangular safe zones using grid boundaries on some sides
    // Options:
    // 1. Full horizontal wall (uses top or bottom boundary): [1..w-1] or [w+1..30]
    // 2. Corner rectangle using 2 boundaries + 2 walls (L-shaped wall)
    // 3. Two horizontal walls enclosing a band

    struct Option {
        int target_r_start, target_r_end, target_c_start, target_c_end;
        std::vector<Point> walls;
        int n_pets;
        int area;
        double score;
    };

    std::vector<Option> options;

    // Single horizontal wall
    for (int w = 3; w <= GRID_SIZE - 2; w++) {
        // Top section [1..w-1]
        int pets_in = 0;
        for (const auto& pet : pets) {
            if (pet.pos.r >= 1 && pet.pos.r <= w - 1) pets_in++;
        }
        int area = (w - 1) * GRID_SIZE;
        double sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
        std::vector<Point> ws;
        for (int c = 1; c <= GRID_SIZE; c++) ws.push_back({w, c});
        options.push_back({1, w - 1, 1, GRID_SIZE, ws, pets_in, area, sc});

        // Bottom section [w+1..30]
        pets_in = 0;
        for (const auto& pet : pets) {
            if (pet.pos.r >= w + 1 && pet.pos.r <= GRID_SIZE) pets_in++;
        }
        area = (GRID_SIZE - w) * GRID_SIZE;
        sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
        ws.clear();
        for (int c = 1; c <= GRID_SIZE; c++) ws.push_back({w, c});
        options.push_back({w + 1, GRID_SIZE, 1, GRID_SIZE, ws, pets_in, area, sc});
    }

    // Corner rectangles (4 corners)
    for (int h = 4; h <= 22; h++) {
        for (int w = 4; w <= 22; w++) {
            // Top-left: [1..h] x [1..w], walls: row h+1 (c=1..w), col w+1 (r=1..h)
            if (h + 1 <= GRID_SIZE && w + 1 <= GRID_SIZE) {
