                std::vector<Point> ws;
                for (int c = 1; c <= w; c++) ws.push_back({h + 1, c});
                for (int r = 1; r <= h; r++) ws.push_back({r, w + 1});
                options.push_back({1, h, 1, w, ws, pets_in, area, sc});
            }

            // Top-right: [1..h] x [30-w+1..30], walls: row h+1 (c=30-w+1..30), col 30-w (r=1..h)
            if (h + 1 <= GRID_SIZE && GRID_SIZE - w >= 1) {
                int c_start = GRID_SIZE - w + 1;
                int c_wall = c_start - 1;
                if (c_wall >= 1) {
                    int pets_in = 0;
                    for (const auto& pet : pets) {
                        if (pet.pos.r >= 1 && pet.pos.r <= h && pet.pos.c >= c_start && pet.pos.c <= GRID_SIZE) pets_in++;
                    }
                    int area = h * w;
                    double sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
                    std::vector<Point> ws;
                    for (int c = c_start; c <= GRID_SIZE; c++) ws.push_back({h + 1, c});
                    for (int r = 1; r <= h; r++) ws.push_back({r, c_wall});
                    options.push_back({1, h, c_start, GRID_SIZE, ws, pets_in, area, sc});
                }
            }

            // Bottom-left: [30-h+1..30] x [1..w], walls: row 30-h (c=1..w), col w+1 (r=30-h+1..30)
            if (GRID_SIZE - h >= 1 && w + 1 <= GRID_SIZE) {
                int r_start = GRID_SIZE - h + 1;
                int r_wall = r_start - 1;
                if (r_wall >= 1) {
                    int pets_in = 0;
                    for (const auto& pet : pets) {
                        if (pet.pos.r >= r_start && pet.pos.r <= GRID_SIZE && pet.pos.c >= 1 && pet.pos.c <= w) pets_in++;
                    }
                    int area = h * w;
                    double sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
                    std::vector<Point> ws;
                    for (int c = 1; c <= w; c++) ws.push_back({r_wall, c});
                    for (int r = r_start; r <= GRID_SIZE; r++) ws.push_back({r, w + 1});
                    options.push_back({r_start, GRID_SIZE, 1, w, ws, pets_in, area, sc});
                }
            }

            // Bottom-right: [30-h+1..30] x [30-w+1..30]
            if (GRID_SIZE - h >= 1 && GRID_SIZE - w >= 1) {
                int r_start = GRID_SIZE - h + 1;
                int r_wall = r_start - 1;
                int c_start = GRID_SIZE - w + 1;
                int c_wall = c_start - 1;
                if (r_wall >= 1 && c_wall >= 1) {
                    int pets_in = 0;
                    for (const auto& pet : pets) {
                        if (pet.pos.r >= r_start && pet.pos.r <= GRID_SIZE && pet.pos.c >= c_start && pet.pos.c <= GRID_SIZE) pets_in++;
                    }
                    int area = h * w;
                    double sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
                    std::vector<Point> ws;
                    for (int c = c_start; c <= GRID_SIZE; c++) ws.push_back({r_wall, c});
                    for (int r = r_start; r <= GRID_SIZE; r++) ws.push_back({r, c_wall});
                    options.push_back({r_start, GRID_SIZE, c_start, GRID_SIZE, ws, pets_in, area, sc});
                }
            }
        }
    }

    // Score each option considering feasibility (wall count vs turns available)
    // Penalize options where walls are too numerous to complete in time
    for (auto& opt : options) {
        int nw = opt.walls.size();
        // Each human can build ~1 wall per 2 turns (move + build). With M humans, ~150*M walls max.
        // But realistically much less. Penalize if nw > reasonable
        double feasibility = 1.0;
        int max_walls = M * 100; // generous estimate
        if (nw > max_walls) {
            feasibility = (double)max_walls / nw;
        }
        opt.score *= feasibility;
    }

    // Pick best
    std::sort(options.begin(), options.end(), [](const Option& a, const Option& b) {
        return a.score > b.score;
    });

    auto best = options[0];

    int target_r_start = best.target_r_start;
    int target_r_end = best.target_r_end;
    int target_c_start = best.target_c_start;
    int target_c_end = best.target_c_end;
    std::vector<Point> walls_needed = best.walls;

    // Sort walls by a sweep order to build efficiently
    // For corner rectangles, build from the corner outward
    Point center_safe = {(target_r_start + target_r_end) / 2, (target_c_start + target_c_end) / 2};

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> tentative_walls;

        // Remove completed walls
        walls_needed.erase(
            std::remove_if(walls_needed.begin(), walls_needed.end(),
                [](const Point& p) { return wall_grid[p.r][p.c]; }),
            walls_needed.end()
        );

        bool building_done = walls_needed.empty();

        if (!building_done) {
            // Sort walls_needed by distance to nearest human (for efficient assignment)
            // Assign each human to nearest unassigned wall
            std::vector<int> assignment(M, -1);
            std::vector<bool> wall_taken(walls_needed.size(), false);

            // Greedy: for each human, find closest wall cell (considering stand position)
            // Process humans in order of who is closest to any wall
            struct HumanWallDist {
                int human_idx, wall_idx, dist;
            };
            std::vector<HumanWallDist> pairs;
            for (int i = 0; i < M; i++) {
                for (int j = 0; j < (int)walls_needed.size(); j++) {
                    Point wc = walls_needed[j];
                    int min_d = INF;
                    for (int d = 0; d < 4; d++) {
                        Point stand = {wc.r + DIRS[d].r, wc.c + DIRS[d].c};
                        if (stand.r < 1 || stand.r > GRID_SIZE || stand.c < 1 || stand.c > GRID_SIZE) continue;
                        if (wall_grid[stand.r][stand.c]) continue;
                        int dist = std::abs(humans[i].pos.r - stand.r) + std::abs(humans[i].pos.c - stand.c);
                        min_d = std::min(min_d, dist);
                    }
                    if (min_d < INF) {
                        pairs.push_back({i, j, min_d});
                    }
                }
            }
            std::sort(pairs.begin(), pairs.end(), [](const HumanWallDist& a, const HumanWallDist& b) {
                return a.dist < b.dist;
            });

            std::vector<bool> human_assigned(M, false);
            for (const auto& p : pairs) {
                if (human_assigned[p.human_idx] || wall_taken[p.wall_idx]) continue;
                assignment[p.human_idx] = p.wall_idx;
                human_assigned[p.human_idx] = true;
                wall_taken[p.wall_idx] = true;
            }

            // Execute actions
            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;

                if (assignment[i] == -1) {
                    // No wall assigned, move to safe center
                    actions[i] = bfs_move(hp, center_safe, tentative_walls);
                    continue;
                }

                Point wc = walls_needed[assignment[i]];

                // Check if adjacent and can build
                bool can_build_now = false;
                int build_dir = -1;
                for (int d = 0; d < 4; d++) {
                    Point target = {hp.r + DIRS[d].r, hp.c + DIRS[d].c};
                    if (target == wc && can_build_wall(wc, i)) {
                        bool already_tent = false;
                        for (const auto& tw : tentative_walls) {
                            if (tw == wc) { already_tent = true; break; }
                        }
                        if (!already_tent) {
                            can_build_now = true;
                            build_dir = d;
                            break;
                        }
                    }
                }

                if (can_build_now) {
                    actions[i] = DIR_BUILD[build_dir];
                    tentative_walls.push_back(wc);
                } else {
                    // Move toward best stand position
                    Point best_stand = {-1, -1};
                    int best_sd = INF;
                    for (int d = 0; d < 4; d++) {
                        Point stand = {wc.r + DIRS[d].r, wc.c + DIRS[d].c};
                        if (stand.r < 1 || stand.r > GRID_SIZE || stand.c < 1 || stand.c > GRID_SIZE) continue;
                        if (wall_grid[stand.r][stand.c]) continue;
                        int sd = std::abs(hp.r - stand.r) + std::abs(hp.c - stand.c);
                        if (sd < best_sd) {
                            best_sd = sd;
                            best_stand = stand;
                        }
                    }
                    if (best_stand.r != -1) {
                        actions[i] = bfs_move(hp, best_stand, tentative_walls);
                    }
                }
            }
        } else {
            // Building done: move humans to safe center area
            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;
                int target_c = target_c_start + 1 + (i * std::max(0, target_c_end - target_c_start - 2)) / std::max(1, M - 1);
                Point target = {(target_r_start + target_r_end) / 2, target_c};
                target.r = std::max(target_r_start, std::min(target_r_end, target.r));
                target.c = std::max(target_c_start, std::min(target_c_end, target.c));

                if (hp == target) {
                    actions[i] = '.';
                } else {
                    actions[i] = bfs_move(hp, target, tentative_walls);
                }
            }
        }

        // Validate actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            Point hpos = humans[i].pos;

            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_BUILD[dd]) { d = dd; break; }
                }
                Point wp = {hpos.r + DIRS[d].r, hpos.c + DIRS[d].c};
                if (!can_build_wall(wp, i)) {
                    actions[i] = '.';
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
                }
                Point np = {hpos.r + DIRS[d].r, hpos.c + DIRS[d].c};
                if (np.r < 1 || np.r > GRID_SIZE || np.c < 1 || np.c > GRID_SIZE || wall_grid[np.r][np.c]) {
                    actions[i] = '.';
                }
            }
        }

        // Output
        std::cout << actions << std::endl;

        // Apply wall builds
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_BUILD[dd]) { d = dd; break; }
                }
                Point wp = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                if (wp.r >= 1 && wp.r <= GRID_SIZE && wp.c >= 1 && wp.c <= GRID_SIZE) {
                    wall_grid[wp.r][wp.c] = true;
                }
            }
        }

        // Apply moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
                }
                Point np = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                if (np.r >= 1 && np.r <= GRID_SIZE && np.c >= 1 && np.c <= GRID_SIZE && !wall_grid[np.r][np.c]) {
                    humans[i].pos = np;
                }
            }
        }

        // Read pet moves
        for (int i = 0; i < N; i++) {
            std::string pmove;
            std::cin >> pmove;
            if (pmove == ".") continue;
            for (char c : pmove) {
                for (int d = 0; d < 4; d++) {
                    if (c == DIR_MOVE[d]) {
                        pets[i].pos.r += DIRS[d].r;
                        pets[i].pos.c += DIRS[d].c;
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
